using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private readonly ShoppingCart _sut = new();

    // --- AddItem ---

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _sut.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(2, _sut.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _sut.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        _sut.AddItem("SKU-1", 2, 10m);
        _sut.AddItem("SKU-1", 3, 10m);

        Assert.AreEqual(5, _sut.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_DifferentSkus_BothExist()
    {
        _sut.AddItem("A", 1, 5m);
        _sut.AddItem("B", 1, 7m);

        Assert.AreEqual(2, _sut.Items.Count);
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", quantity, 10m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", 1, -1m));
    }

    [TestMethod]
    public void AddItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.AddItem(null!, 1, 10m));
    }

    // --- RemoveItem ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-1", 1, 10m);

        _sut.RemoveItem("SKU-1");

        Assert.AreEqual(0, _sut.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_Throws()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _sut.RemoveItem("NOPE"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.RemoveItem(null!));
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _sut.AddItem("A", 2, 10m);  // 20
        _sut.AddItem("B", 3, 5m);   // 15

        Assert.AreEqual(35m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_ZeroPriceItem_ContributesNothing()
    {
        _sut.AddItem("FREE", 5, 0m);

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    // --- ApplyCoupon ---

    [TestMethod]
    [DataRow("SAVE10", 90.00, DisplayName = "SAVE10 gives 10% off")]
    [DataRow("HALF", 50.00, DisplayName = "HALF gives 50% off")]
    public void ApplyCoupon_PercentageCoupons_ReduceTotal(string code, double expectedTotal)
    {
        _sut.AddItem("A", 1, 100m);

        _sut.ApplyCoupon(code);

        Assert.AreEqual((decimal)expectedTotal, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Fiver_SubtractsFiveDollars()
    {
        _sut.AddItem("A", 1, 20m);

        _sut.ApplyCoupon("FIVER");

        Assert.AreEqual(15m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_FiverOnSmallTotal_DoesNotGoBelowZero()
    {
        _sut.AddItem("A", 1, 3m);

        _sut.ApplyCoupon("FIVER");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_Works()
    {
        _sut.AddItem("A", 1, 100m);

        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null code")]
    [DataRow("", DisplayName = "Empty code")]
    [DataRow("   ", DisplayName = "Whitespace code")]
    public void ApplyCoupon_NullOrEmpty_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedByNewCoupon_UsesLatest()
    {
        _sut.AddItem("A", 1, 100m);
        _sut.ApplyCoupon("SAVE10");
        _sut.ApplyCoupon("HALF");

        Assert.AreEqual(50m, _sut.CalculateTotal());
        Assert.AreEqual("HALF", _sut.AppliedCoupon);
    }

    // --- Integration-style scenario ---

    [TestMethod]
    public void FullWorkflow_AddRemoveApplyCoupon_CorrectTotal()
    {
        _sut.AddItem("A", 2, 25m);  // 50
        _sut.AddItem("B", 1, 30m);  // 30
        _sut.RemoveItem("B");       // -30
        _sut.ApplyCoupon("SAVE10"); // 10% off 50 = 45

        Assert.AreEqual(45m, _sut.CalculateTotal());
    }
}

